import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_BASE_URL || '';

/**
 * Create a checkout session.
 * - If REACT_APP_API_BASE_URL is set, POST to `${API_BASE}/checkout`
 * - Otherwise, mock the request locally so the UI can be developed without a backend
 *
 * Expected backend response (recommended):
 *   { checkoutUrl: "https://checkout.stripe.com/..." }
 * OR
 *   { sessionId: "cs_test_..." }  (if you redirect client-side using Stripe.js)
 */
export const createCheckoutSession = (payload) => {
  // DEV MOCK: no backend configured
  if (!API_BASE) {
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve({
          data: {
            mock: true,
            sessionId: `mock_${Date.now()}`,
            // you can either simulate a redirect URL:
            checkoutUrl: `/mock-checkout?amount=${encodeURIComponent(
              String(payload?.amount || '')
            )}`,
            received: payload,
          },
        });
      }, 400);
    });
  }

  // REAL request
  const url = `${API_BASE}/checkout`;
  return axios.post(url, payload, {
    headers: { 'Content-Type': 'application/json' },
  });
};
